import React, { useState } from 'react';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, Legend, ResponsiveContainer } from 'recharts';

export default function WeeklyTimeTracker() {
  const [activities, setActivities] = useState([
    { name: '업무', hours: 40, color: '#3b82f6' },
    { name: '수면', hours: 49, color: '#8b5cf6' },
    { name: '식사', hours: 10.5, color: '#10b981' },
    { name: '운동', hours: 3, color: '#f59e0b' },
    { name: '여가', hours: 20, color: '#ec4899' },
    { name: '기타', hours: 15.5, color: '#6b7280' }
  ]);

  const [newActivity, setNewActivity] = useState({ name: '', hours: '' });
  const [viewMode, setViewMode] = useState('pie');

  const totalHours = activities.reduce((sum, act) => sum + act.hours, 0);
  const weekHours = 168;
  const unusedHours = weekHours - totalHours;

  const handleAddActivity = () => {
    if (newActivity.name && newActivity.hours) {
      const colors = ['#ef4444', '#06b6d4', '#84cc16', '#f97316', '#a855f7', '#14b8a6'];
      const randomColor = colors[Math.floor(Math.random() * colors.length)];

      setActivities([...activities, {
        name: newActivity.name,
        hours: parseFloat(newActivity.hours),
        color: randomColor
      }]);
      setNewActivity({ name: '', hours: '' });
    }
  };

  const handleUpdateHours = (index, newHours) => {
    const updated = [...activities];
    updated[index].hours = parseFloat(newHours) || 0;
    setActivities(updated);
  };

  const handleDelete = (index) => {
    setActivities(activities.filter((_, i) => i !== index));
  };

  const pieData = activities.map(act => ({
    name: act.name,
    value: act.hours,
    percentage: ((act.hours / totalHours) * 100).toFixed(1)
  }));

  const dailyAverage = activities.map(act => ({
    name: act.name,
    hours: (act.hours / 7).toFixed(1),
    color: act.color
  }));

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 p-8">
      <div className="max-w-6xl mx-auto">
        <div className="bg-white rounded-2xl shadow-2xl p-8 mb-8">
          <h1 className="text-4xl font-bold text-gray-800 mb-2">⏰ 주간 시간 사용 분석</h1>
          <p className="text-gray-600 mb-6">일주일 168시간을 어떻게 사용하고 계신가요?</p>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
            <div className="bg-blue-50 rounded-xl p-4">
              <div className="text-sm text-blue-600 font-semibold">전체 시간</div>
              <div className="text-3xl font-bold text-blue-700">168<span className="text-lg">시간</span></div>
            </div>
            <div className="bg-green-50 rounded-xl p-4">
              <div className="text-sm text-green-600 font-semibold">사용 시간</div>
              <div className="text-3xl font-bold text-green-700">{totalHours.toFixed(1)}<span className="text-lg">시간</span></div>
            </div>
            <div className="bg-orange-50 rounded-xl p-4">
              <div className="text-sm text-orange-600 font-semibold">미할당 시간</div>
              <div className="text-3xl font-bold text-orange-700">{unusedHours.toFixed(1)}<span className="text-lg">시간</span></div>
            </div>
          </div>

          <div className="flex gap-4 mb-6">
            <button
              onClick={() => setViewMode('pie')}
              className={`px-6 py-2 rounded-lg font-semibold transition-all ${
                viewMode === 'pie' 
                  ? 'bg-indigo-600 text-white shadow-lg' 
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              📊 비율 보기
            </button>
            <button
              onClick={() => setViewMode('bar')}
              className={`px-6 py-2 rounded-lg font-semibold transition-all ${
                viewMode === 'bar' 
                  ? 'bg-indigo-600 text-white shadow-lg' 
                  : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
              }`}
            >
              📈 일평균 보기
            </button>
          </div>

          {viewMode === 'pie' ? (
            <div className="bg-gradient-to-br from-indigo-50 to-purple-50 rounded-xl p-6">
              <h3 className="text-xl font-bold text-gray-800 mb-4">주간 시간 배분</h3>
              <ResponsiveContainer width="100%" height={400}>
                <PieChart>
                  <Pie
                    data={pieData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    label={({ name, percentage }) => `${name} ${percentage}%`}
                    outerRadius={120}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {activities.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip formatter={(value) => `${value}시간`} />
                </PieChart>
              </ResponsiveContainer>
            </div>
          ) : (
            <div className="bg-gradient-to-br from-indigo-50 to-purple-50 rounded-xl p-6">
              <h3 className="text-xl font-bold text-gray-800 mb-4">일평균 시간</h3>
              <ResponsiveContainer width="100%" height={400}>
                <BarChart data={dailyAverage}>
                  <XAxis dataKey="name" />
                  <YAxis label={{ value: '시간', angle: -90, position: 'insideLeft' }} />
                  <Tooltip formatter={(value) => `${value}시간/일`} />
                  <Bar dataKey="hours" radius={[8, 8, 0, 0]}>
                    {dailyAverage.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          )}
        </div>

        <div className="bg-white rounded-2xl shadow-2xl p-8">
          <h2 className="text-2xl font-bold text-gray-800 mb-6">✏️ 활동 관리</h2>

          <div className="mb-6 p-4 bg-indigo-50 rounded-xl">
            <h3 className="text-lg font-semibold text-gray-800 mb-3">새 활동 추가</h3>
            <div className="flex gap-3">
              <input
                type="text"
                placeholder="활동명 (예: 독서)"
                value={newActivity.name}
                onChange={(e) => setNewActivity({ ...newActivity, name: e.target.value })}
                className="flex-1 px-4 py-2 border-2 border-indigo-200 rounded-lg focus:border-indigo-500 focus:outline-none"
              />
              <input
                type="number"
                placeholder="주당 시간"
                value={newActivity.hours}
                onChange={(e) => setNewActivity({ ...newActivity, hours: e.target.value })}
                className="w-32 px-4 py-2 border-2 border-indigo-200 rounded-lg focus:border-indigo-500 focus:outline-none"
                step="0.5"
                min="0"
              />
              <button
                onClick={handleAddActivity}
                className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition-colors shadow-md"
              >
                추가
              </button>
            </div>
          </div>

          <div className="space-y-3">
            <h3 className="text-lg font-semibold text-gray-800 mb-3">현재 활동 목록</h3>
            {activities.map((activity, index) => (
              <div key={index} className="flex items-center gap-4 p-4 bg-gray-50 rounded-xl hover:bg-gray-100 transition-colors">
                <div
                  className="w-4 h-4 rounded-full flex-shrink-0"
                  style={{ backgroundColor: activity.color }}
                />
                <div className="flex-1 font-semibold text-gray-800">{activity.name}</div>
                <input
                  type="number"
                  value={activity.hours}
                  onChange={(e) => handleUpdateHours(index, e.target.value)}
                  className="w-24 px-3 py-1 border-2 border-gray-300 rounded-lg focus:border-indigo-500 focus:outline-none"
                  step="0.5"
                  min="0"
                />
                <span className="text-gray-600 w-16">시간/주</span>
                <span className="text-gray-500 w-20">({(activity.hours / 7).toFixed(1)}h/일)</span>
                <button
                  onClick={() => handleDelete(index)}
                  className="px-3 py-1 bg-red-500 text-white rounded-lg hover:bg-red-600 transition-colors text-sm font-semibold"
                >
                  삭제
                </button>
              </div>
            ))}
          </div>

          <div className="mt-8 p-6 bg-gradient-to-r from-purple-50 to-pink-50 rounded-xl">
            <h3 className="text-lg font-bold text-gray-800 mb-3">💡 인사이트</h3>
            <div className="space-y-2 text-gray-700">
              <p>• 가장 많은 시간을 사용하는 활동: <span className="font-bold text-indigo-600">
                {activities.length > 0 ? activities.reduce((max, act) => act.hours > max.hours ? act : max).name : '-'}
              </span></p>
              <p>• 미할당 시간이 {unusedHours > 0 ? `${unusedHours.toFixed(1)}시간` : '없습니다'}
                {unusedHours > 0 && ' 있습니다. 이 시간을 어떻게 활용할지 계획해보세요!'}
              </p>
              <p>• 일주일 = 168시간 = {(168/24).toFixed(0)}일 × 24시간</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

